const config = $input.first().json;
const base = config.GitRawBaseURL;
const branch = config.GitBranch || 'dev/breaks-recovery';
const path = config.MappingsPath || 'BreaksRecovery_Main/mappings';

if (!base) {
  throw new Error(
    'System Error: GitRawBaseURL не задан. TDR v3 §6.5: маппинги загружаются из git. Укажите URL raw-файлов в GetConfig.',
  );
}

const baseUrl = String(base).replace(/\/$/, '');
const isStash =
  /stash\.|\/projects\/[^/]+\/repos\//i.test(baseUrl) &&
  !baseUrl.includes('raw.githubusercontent.com');

const files = [
  'activity',
  'container',
  'news_reading',
  'news_exception_skills',
  'fte_groups',
  'email_fallback',
  'fte_thresholds',
  'runtime',
];

function buildMappingUrl(file) {
  if (isStash) {
    const at = branch.startsWith('refs/') ? branch : `refs/heads/${branch}`;
    return `${baseUrl}/${path}/${file}.json?at=${encodeURIComponent(at)}`;
  }
  return `${baseUrl}/${branch}/${path}/${file}.json`;
}

const staticData = $getWorkflowStaticData('global');
staticData.config = config;
staticData.files = files;

return files.map((file) => ({
  json: {
    url: buildMappingUrl(file),
  },
}));

const staticData = $getWorkflowStaticData('global');
const config = staticData.config;
const files = staticData.files;

if (!config || !Array.isArray(files) || files.length === 0) {
  throw new Error(
    'System Error: LoadMappings — нет контекста GetConfig. Запускайте из Main после Restore Config Context.',
  );
}

const items = $input.all();
if (items.length !== files.length) {
  throw new Error(
    `System Error: LoadMappings — ожидалось ${files.length} ответов HTTP, получено ${items.length}. ` +
      'JSON-массив разбился на items: в Fetch JSON → Options → Response → Response Format = Text.',
  );
}

const mappings = {};
for (let i = 0; i < files.length; i++) {
  const raw = items[i].json;
  let body = raw?.mapping_body;

  if (body === undefined) {
    const text =
      typeof raw === 'string'
        ? raw
        : typeof raw?.data === 'string'
          ? raw.data
          : typeof raw?.body === 'string'
            ? raw.body
            : null;
    if (text) {
      body = JSON.parse(text);
    } else if (Array.isArray(raw) || (raw && !raw.url && typeof raw === 'object')) {
      body = raw;
    } else {
      throw new Error(
        `System Error: LoadMappings — не удалось разобрать ${files[i]}.json. В Fetch JSON: Response Format = Text.`,
      );
    }
  }

  if (body === undefined || body === null) {
    throw new Error(`System Error: LoadMappings — пустой ответ для ${files[i]}.json`);
  }
  mappings[files[i]] = body;
}

delete staticData.config;
delete staticData.files;

return [
  {
    json: {
      ...config,
      mappings,
      mappings_loaded_at: new Date().toISOString(),
    },
  },
];
